    totals = {}
    for entry in entries:
        if ":" not in entry:
            continue
        key, raw_value = entry.split(":", 1)
        key = key.strip().lower()
        if not key:
            continue
        try:
            value = int(raw_value.strip())
        except ValueError:
            continue
        totals[key] = totals.get(key, 0) + value
    if not totals:
        return ""
    best_key = ""
    best_total = None
    for key in sorted(totals):
        total = totals[key]
        if best_total is None or total > best_total:
            best_key = key
            best_total = total
    return best_key

