            transform(value.begin(), value.end(), value.begin(), ::tolower);
            if (!key.empty() && !value.empty()) latest[key] = value;
        }
        if (end == string::npos) break;
        start = end + 1;
    }
    string out;
    for (const auto& item : latest) {
        if (!out.empty()) out += "&";
        out += item.first + "=" + item.second;
    }
    return out;
}

